import React from 'react';
import { useLocation, Link } from 'react-router-dom';

function PaymentSuccess() {
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);
  const trxId = queryParams.get('trxId');
  const amount = queryParams.get('amount');

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", background: "#051218", color: "white", padding: 20, textAlign: "center" }}>
      <div style={{ fontSize: "4rem", marginBottom: 20 }}>🎉</div>
      <h1 style={{ fontFamily: "'Cinzel Decorative',cursive", color: "#D4AF37", marginBottom: 10 }}>Payment Successful!</h1>
      <p style={{ fontSize: "1.2rem", color: "rgba(255,255,255,0.8)", maxWidth: 400 }}>
        Alhamdulillah! Your Salami of <strong>৳{amount}</strong> has been successfully added to the gift box.
      </p>
      
      <div style={{ margin: "30px 0", padding: "15px 30px", background: "rgba(212,175,55,0.1)", border: "1px solid #D4AF37", borderRadius: 12 }}>
        <p style={{ margin: 0, fontSize: "0.9rem", color: "rgba(255,255,255,0.6)" }}>Transaction ID</p>
        <p style={{ margin: 0, fontSize: "1.2rem", fontFamily: "monospace", color: "white" }}>{trxId}</p>
      </div>

      <Link to="/" style={{ padding: "12px 24px", background: "transparent", border: "1px solid #D4AF37", color: "#D4AF37", borderRadius: 8, textDecoration: "none", fontWeight: "bold" }}>
        Return to Home
      </Link>
    </div>
  );
}

export default PaymentSuccess;
